server"><rect x="430.62" y="316.75" width="20.25" height="14.58" rx="2" fill="#ffffff" stroke="#e2e8f0" stroke-width="1.10"/><line x1="434.26" y1="321.80" x2="447.22" y2="321.80" stroke="#e2e8f0" stroke-width="1"/><line x1="434.26" y1="325.45" x2="447.22" y2="325.45" stroke="#e2e8f0" stroke-width="1"/></g><text x="440.74" y="380.25" text-anchor="middle" font-family="&#39;Inter&#39;, -apple-system, BlinkMacSystemFont, &#39;Segoe UI&#39;, Roboto, Helvetica, Arial, sans-serif" font-size="15" fill="#1a1a2e">Redis Cache</text><title>Node: Redis Cache, rectangle</title></g></svg>

